package main

import (
	"context"
	"fmt"
	"net/http"
	"net/http/pprof"
	"os"
	"sync"
	"sync/atomic"
	"time"

	"cat-service/config"
	"cat-service/internal/adapter"
	"cat-service/internal/adapter/metric"
	"cat-service/internal/health"
	"cat-service/internal/helper"
	"cat-service/internal/repository"
	"cat-service/internal/usecase"

	"github.com/robfig/cron/v3"
	"go.elastic.co/apm/v2"
	"go.uber.org/fx"
	"go.uber.org/fx/fxevent"
	"go.uber.org/zap"
)

var (
	processedCatServiceTotal uint64
)

// gatherCustomMetrics is function APM agent will call frequently to collect metrics
func gatherCustomMetrics(_ context.Context, metrics *apm.Metrics) error {
	metrics.Add("cat_service_total",
		[]apm.MetricLabel{{Name: "type", Value: "api"}},
		float64(atomic.LoadUint64(&processedCatServiceTotal)),
	)

	// --- Active gRPC pool clients (gauge) ---
	metrics.Add("cat_service_grpc_cfappdb_active",
		nil,
		float64(metric.GetActiveGrpcCfAppDb()),
	)
	return nil
}

type httpServerDeps struct {
	fx.In

	Lifecycle     fx.Lifecycle
	Logger        *zap.Logger
	Config        *config.Config
	HealthChecker *health.Checker
	Usecase       usecase.ICatServiceUsecase
}

func main() {
	if tr := apm.DefaultTracer(); tr != nil && tr.Recording() {
		tr.RegisterMetricsGatherer(apm.GatherMetricsFunc(gatherCustomMetrics))
		zap.L().Info("Custom metrics gatherer registered with Elastic APM.")
	}

	app := fx.New(
		fx.WithLogger(func(log *zap.Logger) fxevent.Logger {
			return &fxevent.ConsoleLogger{W: os.Stderr}
		}),
		fx.Provide(
			config.Load,
			health.NewChecker,
			NewHealthServer,
		),
		helper.Provide(),
		repository.Provide(),
		adapter.Provide(),
		usecase.Provide(),
		fx.Invoke(
			func(*http.Server) {},
		),
		fx.Invoke(
			runScheduler,
		),
	)

	app.Run()
}

func runScheduler(lc fx.Lifecycle, logger *zap.Logger, cfg *config.Config, uc usecase.ICatServiceUsecase) {
	c := cron.New(cron.WithSeconds())

	lc.Append(fx.Hook{
		OnStart: func(ctx context.Context) error {
			_, err := c.AddFunc(cfg.JobCfg.CronSchedule, func() {
				runJob(logger, uc)
			})
			if err != nil {
				logger.Error("Failed to add cron schedule", zap.String("ErrMsg", err.Error()))
				return err
			}

			logger.Info("Cron scheduler started",
				zap.String("CatServCronSchedule", cfg.JobCfg.CronSchedule),
				zap.Int("CatServTotalRecordsPerRun", cfg.JobCfg.TotalRecordsPerRun),
				zap.Int("CatServMaximumRecordsPerRun", cfg.JobCfg.MaximumRecordsPerRun),
				zap.Int("CatServBatchSize", cfg.JobCfg.BatchSize),
				zap.Int("CatServChunkSize", cfg.JobCfg.ChunkSize),
				zap.Int("CatServWorkerCount", cfg.JobCfg.WorkerCount),
				zap.Int("CatServMaxRetry", cfg.JobCfg.MaxRetry),
			)
			c.Start()
			return nil
		},
		OnStop: func(ctx context.Context) error {
			logger.Info("Stopping cron scheduler")
			ctx2 := c.Stop()
			<-ctx2.Done()
			return nil
		},
	})
}

var jobRunning sync.Mutex

func runJob(logger *zap.Logger, uc usecase.ICatServiceUsecase) {
	// Skip if previous job is still running
	if !jobRunning.TryLock() {
		logger.Warn("Skipping job run: previous job still in progress")
		return
	}
	defer jobRunning.Unlock()

	// Start APM transaction for the job run
	tx := apm.DefaultTracer().StartTransaction("catService.Run", "cronjob")
	defer tx.End()
	ctx := apm.ContextWithTransaction(context.Background(), tx)

	if err := uc.Run(ctx); err != nil {
		apm.CaptureError(ctx, err).Send()
		logger.Error("Job failed", zap.String("ErrMsg", err.Error()))
		return
	}
	logger.Debug("Job completed successfully")
}

func NewHealthServer(deps httpServerDeps) *http.Server {
	mux := http.NewServeMux()
	mux.Handle("/healthz", deps.HealthChecker.LivenessHandler())
	mux.Handle("/readyz", deps.HealthChecker.ReadinessHandler())
	mux.Handle("/startupz", deps.HealthChecker.StartupHandler())

	// pprof endpoints — exposed under /debug/pprof/* for runtime profiling
	mux.HandleFunc("/debug/pprof/", pprof.Index)
	mux.HandleFunc("/debug/pprof/cmdline", pprof.Cmdline)
	mux.HandleFunc("/debug/pprof/profile", pprof.Profile)
	mux.HandleFunc("/debug/pprof/symbol", pprof.Symbol)
	mux.HandleFunc("/debug/pprof/trace", pprof.Trace)

	// Manual job trigger endpoint
	mux.HandleFunc("/trigger", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
			return
		}
		go runJob(deps.Logger, deps.Usecase)
		w.WriteHeader(http.StatusAccepted)
		w.Write([]byte(`{"message":"job triggered"}`))
	})

	srv := &http.Server{
		Addr:              fmt.Sprintf(":%s", deps.Config.Base.HttpAddress),
		Handler:           mux,
		ReadHeaderTimeout: 5 * time.Second,
	}

	deps.Lifecycle.Append(fx.Hook{
		OnStart: func(_ context.Context) error {
			deps.Logger.Info("Starting health HTTP server", zap.String("addr", srv.Addr))
			go func() {
				if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
					deps.Logger.Error("Health HTTP server failed", zap.Error(err))
				}
			}()
			deps.HealthChecker.SetStartupComplete(true)
			deps.HealthChecker.SetReady(true)
			deps.Logger.Info("Health check: service marked as ready")
			return nil
		},
		OnStop: func(ctx context.Context) error {
			deps.HealthChecker.SetReady(false)
			deps.Logger.Info("Health check: service marked as not ready (shutting down)")
			return srv.Shutdown(ctx)
		},
	})
	return srv
}

