package metric

import (
	"sync/atomic"
)

var (

	// ActiveGrpcCfAppDb is the total number of active sessions in FPS service for CfAppDb
	ActiveGrpcCfAppDb int64

	// ActiveGrpcDwsasDb is the total number of active sessions in FPS service for DwsasDb
	ActiveGrpcDwsasDb int64

	// ActiveGrpcCifDb is the total number of active sessions in FPS service for CifDb
	ActiveGrpcCifDb int64

	// ActiveGrpcFinnone is the total number of active sessions in FPS service for CifDb
	ActiveGrpcFinnone int64
)

// GetActiveGrpcCfAppDb returns the current value of active grpc connection to CfAppDb pool service
func GetActiveGrpcCfAppDb() int64 {
	return atomic.LoadInt64(&ActiveGrpcCfAppDb)
}

// SetActiveGrpcCfAppDb sets the value of active grpc connection to CfAppDb pool service
func SetActiveGrpcCfAppDb(value int64) {
	atomic.StoreInt64(&ActiveGrpcCfAppDb, value)
}

// IncrementActiveGrpcCfAppDb increments value of active grpc connection to CfAppDb pool service by 1.
func IncrementActiveGrpcCfAppDb() {
	atomic.AddInt64(&ActiveGrpcCfAppDb, 1)
}

// DecrementActiveGrpcCfAppDb decrements value of active grpc connection to CfAppDb pool service by 1.
func DecrementActiveGrpcCfAppDb() {
	atomic.AddInt64(&ActiveGrpcCfAppDb, -1)
}

// GetActiveGrpcDwsasDb returns the current value of active grpc connection to DwsasDb pool service
func GetActiveGrpcDwsasDb() int64 {
	return atomic.LoadInt64(&ActiveGrpcDwsasDb)
}

// SetActiveGrpcDwsasDb sets the value of active grpc connection to DwsasDb pool service
func SetActiveGrpcDwsasDb(value int64) {
	atomic.StoreInt64(&ActiveGrpcDwsasDb, value)
}

// IncrementActiveGrpcDwsasDb increments value of active grpc connection to DwsasDb pool service by 1.
func IncrementActiveGrpcDwsasDb() {
	atomic.AddInt64(&ActiveGrpcDwsasDb, 1)
}

// DecrementActiveGrpcDwsasDb decrements value of active grpc connection to DwsasDb pool service by 1.
func DecrementActiveGrpcDwsasDb() {
	atomic.AddInt64(&ActiveGrpcDwsasDb, -1)
}

// GetActiveGrpcCifDb returns the current value of active grpc connection to CifDb pool service
func GetActiveGrpcCifDb() int64 {
	return atomic.LoadInt64(&ActiveGrpcCifDb)
}

// SetActiveGrpcCifDb sets the value of active grpc connection to CifDb pool service
func SetActiveGrpcCifDb(value int64) {
	atomic.StoreInt64(&ActiveGrpcCifDb, value)
}

// IncrementActiveGrpcCifDb increments value of active grpc connection to CifDb pool service by 1.
func IncrementActiveGrpcCifDb() {
	atomic.AddInt64(&ActiveGrpcCifDb, 1)
}

// DecrementActiveGrpcCifDb decrements value of active grpc connection to CifDb pool service by 1.
func DecrementActiveGrpcCifDb() {
	atomic.AddInt64(&ActiveGrpcCifDb, -1)
}

// GetActiveGrpcFinnone returns the current value of active grpc connection to Finnone pool service
func GetActiveGrpcFinnone() int64 {
	return atomic.LoadInt64(&ActiveGrpcFinnone)
}

// SetActiveGrpcFinnone sets the value of active grpc connection to Finnone pool service
func SetActiveGrpcFinnone(value int64) {
	atomic.StoreInt64(&ActiveGrpcFinnone, value)
}

// IncrementActiveGrpcFinnone increments value of active grpc connection to Finnone pool service by 1.
func IncrementActiveGrpcFinnone() {
