}

package metric

import (
	"testing"

	"github.com/stretchr/testify/assert"
)

func TestCfAppDb_IncrementDecrement(t *testing.T) {
	SetActiveGrpcCfAppDb(0)
	IncrementActiveGrpcCfAppDb()
	IncrementActiveGrpcCfAppDb()
	assert.Equal(t, int64(2), GetActiveGrpcCfAppDb())
	DecrementActiveGrpcCfAppDb()
	assert.Equal(t, int64(1), GetActiveGrpcCfAppDb())
}

func TestDwsasDb_IncrementDecrement(t *testing.T) {
	SetActiveGrpcDwsasDb(0)
	IncrementActiveGrpcDwsasDb()
	assert.Equal(t, int64(1), GetActiveGrpcDwsasDb())
	DecrementActiveGrpcDwsasDb()
	assert.Equal(t, int64(0), GetActiveGrpcDwsasDb())
}

func TestCifDb_SetAndGet(t *testing.T) {
	SetActiveGrpcCifDb(10)
	assert.Equal(t, int64(10), GetActiveGrpcCifDb())
	IncrementActiveGrpcCifDb()
	assert.Equal(t, int64(11), GetActiveGrpcCifDb())
	DecrementActiveGrpcCifDb()
	assert.Equal(t, int64(10), GetActiveGrpcCifDb())
}

func TestFinnone_SetAndGet(t *testing.T) {
	SetActiveGrpcFinnone(5)
	assert.Equal(t, int64(5), GetActiveGrpcFinnone())
	IncrementActiveGrpcFinnone()
	assert.Equal(t, int64(6), GetActiveGrpcFinnone())
	DecrementActiveGrpcFinnone()
	assert.Equal(t, int64(5), GetActiveGrpcFinnone())
}

