package model

import (
	"cat-service/internal/dto"
	"cat-service/internal/util"
	"fmt"
	"strings"
)

// W4PaymentServiceResponse is our internal result passed to usecase
type W4PaymentServiceResponse struct {
	IsSuccess   bool
	IsRetryable bool
}

// W4PaymentXMLResponse represents the XML response from W4 payment service
type W4PaymentXMLResponse struct {
	Code      string        `xml:"Code"`
	Message   string        `xml:"Message"`
	Timestamp string        `xml:"Timestamp"`
	RequestID string        `xml:"RequestId"`
	Data      W4PaymentData `xml:"Data"`
}

type W4PaymentData struct {
	TotalReceived int               `xml:"totalReceived"`
	TotalSaved    int               `xml:"totalSaved"`
	TotalSkipped  int               `xml:"totalSkipped"`
	Details       []W4PaymentDetail `xml:"details"`
}

// W4PaymentDetail represents per-record result in a batch response
type W4PaymentDetail struct {
	Code               string `xml:"code"`
	Message            string `xml:"message"`
	IpatID             string `xml:"ipatId"`
	LiabContractNumber string `xml:"liabContractNumber"`
}

// ProcessResult holds the outcome of processing a single record
type ProcessResult struct {
	RecordID    string
	IsSuccess   bool
	IsRetryable bool
	RetryCount  string
}

// BuildBatchPayload builds the XML payload for W4 payment service
func BuildBatchPayload(records []dto.Record) string {
	var b strings.Builder
	b.WriteString("<CatPaymentBatchRequest>")
	for _, r := range records {
		fmt.Fprintf(&b, `<CatPaymentRequest><LiabContractNumber>%s</LiabContractNumber><PaymentAmount>%s</PaymentAmount><IpatId>%s</IpatId><IpatExChannel>%s</IpatExChannel><IpatTransType>%s</IpatTransType><IpatTransDate>%s</IpatTransDate><IpatTransDescription>%s</IpatTransDescription><IpatExCompany>%s</IpatExCompany></CatPaymentRequest>`,
			r.ContractNum, r.TransAmount, r.TransCode, r.ExChannel, r.TransType, util.FormatISOToDateOnly(r.TransDate), r.TransDesc, r.ExCompany)
	}
	b.WriteString("</CatPaymentBatchRequest>")
	return b.String()
}

files.internal/adapter/w4_payment_client.go:
package adapter

import (
	"bytes"
	"context"
	"encoding/base64"
	"encoding/xml"
	"esb-go-libs/util"
	"fmt"
	"io"
	"net"
	"net/http"
	"time"

	"cat-service/config"
	"cat-service/internal/adapter/model"
	"cat-service/internal/dto"

	"go.elastic.co/apm/v2"
	"go.uber.org/zap"
)

type IW4PaymentServiceClient interface {
	ProcessRecords(ctx context.Context, records []dto.Record) []model.ProcessResult
}

type externalServiceClient struct {
	httpClient        *http.Client
	url               string
	basicAuth         string
	logger            *zap.Logger
	recordsPerRequest int
}

func NewW4PaymentServiceClient(cfg *config.Config, logger *zap.Logger) IW4PaymentServiceClient {
	transport := &http.Transport{
		MaxIdleConns:        100,
		MaxIdleConnsPerHost: 100,
		MaxConnsPerHost:     100,
		IdleConnTimeout:     90 * time.Second,
		TLSHandshakeTimeout: 10 * time.Second,
		DisableKeepAlives:   false,
		DialContext: (&net.Dialer{
			Timeout:   10 * time.Second,
			KeepAlive: 30 * time.Second,
		}).DialContext,
	}

	recordsPerReq := max(cfg.W4PaymentServiceCfg.RecordsPerRequest, 1)

	return &externalServiceClient{
		httpClient: &http.Client{
			Timeout:   time.Duration(cfg.W4PaymentServiceCfg.TimeoutSeconds) * time.Second,
			Transport: transport,
		},
		url:               cfg.W4PaymentServiceCfg.URL + cfg.W4PaymentServiceCfg.PathPayment,
		basicAuth:         "Basic " + base64.StdEncoding.EncodeToString([]byte(cfg.W4PaymentServiceCfg.Username+":"+cfg.W4PaymentServiceCfg.Password)),
		logger:            logger,
		recordsPerRequest: recordsPerReq,
	}
}

// ProcessRecords sends records in a single HTTP request to the external service
func (c *externalServiceClient) ProcessRecords(ctx context.Context, records []dto.Record) []model.ProcessResult {
	return c.processBatch(ctx, records)
}

// processBatch sends a batch of records in a single HTTP request
func (c *externalServiceClient) processBatch(ctx context.Context, batch []dto.Record) []model.ProcessResult {
	// APM config
	span, ctx := apm.StartSpan(ctx, "catService.adapter.processBatch", "adapter")
	defer span.End()
	span.Context.SetLabel("BatchSize", fmt.Sprintf("%d", len(batch)))

	// Build payload from batch records
	payload := model.BuildBatchPayload(batch)
	body := bytes.NewBufferString(payload)

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, c.url, body)
	if err != nil {
		c.logger.Error("Failed to create request",
			zap.Int("BatchSize", len(batch)),
			zap.String("ErrMsg", err.Error()),
		)
		return c.markAllRetryable(batch)
	}
	var ourRequestID = util.GenTransID()

	req.Header.Set("Content-Type", "application/xml")
	req.Header.Set("Authorization", c.basicAuth)
	req.Header.Set("Accept", "application/xml")
	req.Header.Set("X-RequestID", ourRequestID)

	resp, err := c.httpClient.Do(req)
	if err != nil {
		c.logger.Error("HTTP request failed",
			zap.Int("BatchSize", len(batch)),
			zap.String("ErrMsg", err.Error()),
			zap.String("OurRequestID", ourRequestID),
		)
		return c.markAllRetryable(batch)
	}
	defer resp.Body.Close()

	bodyBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		c.logger.Error("Failed to read response body",
			zap.Int("BatchSize", len(batch)),
			zap.String("ErrMsg", err.Error()),
			zap.String("OurRequestID", ourRequestID),
		)
		return c.markAllFailed(batch)
	}

	var xmlResp model.W4PaymentXMLResponse
	if err := xml.Unmarshal(bodyBytes, &xmlResp); err != nil {
		c.logger.Error("Failed to decode XML response",
			zap.Int("BatchSize", len(batch)),
			zap.String("W4RespBody", string(bodyBytes)),
			zap.String("OurRequestID", ourRequestID),
			zap.String("ErrMsg", err.Error()),
			zap.Int("W4RespStatusCode", resp.StatusCode),
		)
		return c.markAllFailed(batch)
	}

	// Map response code to result for all records in batch
	return c.mapResponseToResults(batch, xmlResp, bodyBytes, ourRequestID)
}

// mapResponseToResults maps the W4 response to ProcessResult for each record in batch
// Code "000": batch accepted — check per-record <details> for individual failures
// Code != "000": batch-level error — apply to all records
func (c *externalServiceClient) mapResponseToResults(batch []dto.Record, xmlResp model.W4PaymentXMLResponse, rawBody []byte, ourRequestID string) []model.ProcessResult {
	results := make([]model.ProcessResult, len(batch))

	// Batch-level error (non-000 code)
	if xmlResp.Code != "000" {
		var isRetryable bool
		switch xmlResp.Code {
		case "408", "300": // timeout/processing error - retryable
			isRetryable = true
			c.logger.Debug("W4 batch-level retryable error",
				zap.String("OurRequestID", ourRequestID),
				zap.String("W4RespRequestID", xmlResp.RequestID),
				zap.String("W4RespCode", xmlResp.Code),
				zap.String("W4RespMessage", xmlResp.Message),
			)
		default: // other codes - non-retryable
			isRetryable = false
			c.logger.Error("W4 batch-level non-retryable error",
				zap.String("W4RespRequestID", xmlResp.RequestID),
				zap.String("OurRequestID", ourRequestID),
				zap.String("W4RespCode", xmlResp.Code),
				zap.String("W4RespMessage", xmlResp.Message),
				zap.String("W4RespRaw", string(rawBody)),
			)
		}
		for i, rec := range batch {
			results[i] = model.ProcessResult{
				RecordID:    rec.ID,
				IsSuccess:   false,
				IsRetryable: isRetryable,
				RetryCount:  rec.RetryCount,
			}
		}
		return results
	}

	// Code "000": batch accepted — build lookup of per-record detail codes by IpatId (TransCode)
	detailByIpatID := make(map[string]model.W4PaymentDetail, len(xmlResp.Data.Details))
	for _, d := range xmlResp.Data.Details {
		detailByIpatID[d.IpatID] = d
	}

	// Map each record: if it appears in details, check its code; otherwise it's success
	for i, rec := range batch {
		detail, hasDetail := detailByIpatID[rec.TransCode]
		if !hasDetail { // W4_payment receive successfully
			// Not in details = save successfully
			results[i] = model.ProcessResult{
				RecordID:    rec.ID,
				IsSuccess:   true,
				IsRetryable: false,
				RetryCount:  rec.RetryCount,
			}
			continue
		}

		// Per-record detail code mapping
		switch detail.Code {
		case "202": // IpatId already exists - mark as success
			c.logger.Debug("W4Resp: IpatId of the selected LIAB already exists; dupplicated; mark as success",
				zap.String("W4RespRequestID", xmlResp.RequestID),
				zap.String("RecordID", rec.ID),
				zap.String("OurRequestID", ourRequestID),
				zap.String("TransCode", rec.TransCode),
				zap.String("ContractNumber", rec.ContractNum),
				zap.String("W4RespDetailCode", detail.Code),
				zap.String("W4RespDetailMessage", detail.Message),
			)
			results[i] = model.ProcessResult{RecordID: rec.ID, IsSuccess: true, IsRetryable: false, RetryCount: rec.RetryCount}
		case "201": // payment amount invalid - non-retryable
			c.logger.Debug("W4Resp: payment amount must be greater than 0; mark as failed",
				zap.String("W4RespRequestID", xmlResp.RequestID),
				zap.String("RecordID", rec.ID),
				zap.String("OurRequestID", ourRequestID),
				zap.String("TransCode", rec.TransCode),
				zap.String("ContractNumber", rec.ContractNum),
				zap.String("W4RespDetailCode", detail.Code),
				zap.String("W4RespDetailMessage", detail.Message),
			)
			results[i] = model.ProcessResult{RecordID: rec.ID, IsSuccess: false, IsRetryable: false, RetryCount: rec.RetryCount}
		case "203": // No active contracts found - mark as false
			c.logger.Debug("W4Resp: No active contracts found. Not W4 scope; mark as failed",
				zap.String("W4RespRequestID", xmlResp.RequestID),
				zap.String("RecordID", rec.ID),
				zap.String("OurRequestID", ourRequestID),
				zap.String("TransCode", rec.TransCode),
				zap.String("ContractNumber", rec.ContractNum),
				zap.String("W4RespDetailCode", detail.Code),
				zap.String("W4RespDetailMessage", detail.Message),
			)
			results[i] = model.ProcessResult{RecordID: rec.ID, IsSuccess: false, IsRetryable: false, RetryCount: rec.RetryCount}
		case "211": // IpatTransType must be 'CARD', 'CASHBACK' - mark as false
			c.logger.Debug("W4Resp: IpatTransType must be 'CARD', 'CASHBACK'. Not W4 transType; mark as failed",
				zap.String("W4RespRequestID", xmlResp.RequestID),
				zap.String("RecordID", rec.ID),
				zap.String("OurRequestID", ourRequestID),
				zap.String("TransCode", rec.TransCode),
				zap.String("ContractNumber", rec.ContractNum),
				zap.String("W4RespDetailCode", detail.Code),
				zap.String("W4RespDetailMessage", detail.Message),
			)
			results[i] = model.ProcessResult{RecordID: rec.ID, IsSuccess: false, IsRetryable: false, RetryCount: rec.RetryCount}
		default: // unknown detail code non - retryable
			c.logger.Error("W4 per-record unknown code, mark as fail",
				zap.String("W4RespRequestID", xmlResp.RequestID),
				zap.String("RecordID", rec.ID),
				zap.String("OurRequestID", ourRequestID),
				zap.String("TransCode", rec.TransCode),
				zap.String("ContractNumber", rec.ContractNum),
				zap.String("DetailCode", detail.Code),
				zap.String("DetailMessage", detail.Message),
			)
			results[i] = model.ProcessResult{RecordID: rec.ID, IsSuccess: false, IsRetryable: false, RetryCount: rec.RetryCount}
		}
	}
	c.logger.Info("Request to W4/payment: batch processed",
		zap.String("W4RespRequestID", xmlResp.RequestID),
		zap.String("OurRequestID", ourRequestID),
		zap.Int("W4TotalReceived", xmlResp.Data.TotalReceived),
		zap.Int("W4TotalSaved", xmlResp.Data.TotalSaved),
		zap.Int("W4TotalSkipped", xmlResp.Data.TotalSkipped),
	)
	return results
}

// markAllRetryable marks all records in batch as retryable failure
func (c *externalServiceClient) markAllRetryable(batch []dto.Record) []model.ProcessResult {
	results := make([]model.ProcessResult, len(batch))
	for i, rec := range batch {
		results[i] = model.ProcessResult{
			RecordID:    rec.ID,
			IsSuccess:   false,
			IsRetryable: true,
			RetryCount:  rec.RetryCount,
		}
	}
	return results
}

// markAllFailed marks all records in batch as non-retryable failure
func (c *externalServiceClient) markAllFailed(batch []dto.Record) []model.ProcessResult {
	results := make([]model.ProcessResult, len(batch))
	for i, rec := range batch {
		results[i] = model.ProcessResult{
			RecordID:    rec.ID,
			IsSuccess:   false,
			IsRetryable: false,
			RetryCount:  rec.RetryCount,
		}
	}
	return results
}

