type ICatServiceRepository interface {
	CaptureRecords(ctx context.Context, jobID string, batchSize int, releaseSeconds int) ([]dto.Record, error)
	UpdateStatusSent(ctx context.Context, recordIDs []string, jobID string) error
	UpdateStatusFail(ctx context.Context, recordIDs []string, jobID string) error
	UpdateStatusRetry(ctx context.Context, recordIDs []string, retryStatus string, jobID string) error
	ExtendRelease(ctx context.Context, jobID string, extendSeconds int) error
	SyncStatusToMain(ctx context.Context, jobID string) error
}

type catServiceRepository struct {
	cfg            *config.Config
	logger         *zap.Logger
	cfAppDbAdapter dbadapter.IPoolAPIAdapter
}

func NewCatServiceRepository(
	cfg *config.Config,
	logger *zap.Logger,
	params struct {
		fx.In
		CfAppDbAdapter dbadapter.IPoolAPIAdapter `name:"CfAppDbAdapter"`
	},
) ICatServiceRepository {
	return &catServiceRepository{
		cfg:            cfg,
		logger:         logger,
		cfAppDbAdapter: params.CfAppDbAdapter,
	}
}

// CaptureRecords calls SP_A via pool service
func (r *catServiceRepository) CaptureRecords(ctx context.Context, jobID string, batchSize int, releaseSeconds int) ([]dto.Record, error) {
	// APM config
	span, ctx := apm.StartSpan(ctx, "catService.repository.CaptureRecords", "repository")
	defer span.End()
	span.Context.SetLabel("JobID", jobID)

	statement := `BEGIN APP_ESB_MICROSVC.SP_CAT_CAPTURE_REPAYMENTS(:P_JOB_ID, :P_BATCH_SIZE, :P_RELEASE_SEC, :P_STATUS, :P_CURSOR); END;`

	req := &model.PoolServiceRequest{
		Sys: model.SysReq{
			TransID:     jobID,
			RequestorID: r.cfg.App,
			DateTime:    time.Now().Format(time.RFC3339),
		},
		QueryString: statement,
		InputParameters: []model.QueryParam{
			{Name: "P_JOB_ID", Value: jobID, DataType: "VARCHAR2"},
			{Name: "P_BATCH_SIZE", Value: fmt.Sprintf("%d", batchSize), DataType: "NUMBER"},
			{Name: "P_RELEASE_SEC", Value: fmt.Sprintf("%d", releaseSeconds), DataType: "NUMBER"},
		},
		OutputParameters: []model.QueryParam{
			{Name: "P_STATUS", Value: "", DataType: "NUMBER"},
			{Name: "P_CURSOR", Value: "", DataType: "CURSOR"},
		},
	}

	result, err := r.cfAppDbAdapter.PoolExecuteQuery(ctx, req, r.cfg.CfAppDbClient.Username, r.cfg.CfAppDbClient.Password)
	if err != nil {
		r.logger.Error("SP_CAT_CAPTURE_REPAYMENTS failed",
			zap.String("JobID", jobID),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("SP_CAT_CAPTURE_REPAYMENTS failed: %w", err)
	}

	if result.Sys.Code == 3 {
		r.logger.Debug(
			"SP_CAT_CAPTURE_REPAYMENTS: nothing to process",
			zap.String("JobID", jobID),
		)
		return nil, nil
	}

	// Single unmarshal — result.Results structure: {"out_params":{"P_STATUS":0,"P_CURSOR":{"rows":[...]}}}
	var response struct {
		OutParams struct {
			PStatus int64 `json:"P_STATUS"`
			PCursor struct {
				Rows []dto.Record `json:"rows"`
			} `json:"P_CURSOR"`
		} `json:"out_params"`
	}
	if err := sonic.UnmarshalString(result.Results, &response); err != nil {
		r.logger.Error("Failed to unmarshal SP_CAT_CAPTURE_REPAYMENTS result",
			zap.String("JobID", jobID),
			zap.String("ErrMsg", err.Error()),
		)
		return nil, fmt.Errorf("failed to unmarshal SP_CAT_CAPTURE_REPAYMENTS: %w", err)
	}

	if response.OutParams.PStatus == 3 {
		r.logger.Debug(
			"SP_CAT_CAPTURE_REPAYMENTS: nothing to process",
			zap.String("JobID", jobID),
		)
		return nil, nil
	}
	if response.OutParams.PStatus != 0 {
		r.logger.Error("SP_CAT_CAPTURE_REPAYMENTS returned error status",
			zap.String("JobID", jobID),
			zap.Int64("Status", response.OutParams.PStatus),
		)
		return nil, fmt.Errorf("SP_CAT_CAPTURE_REPAYMENTS returned status: %d", response.OutParams.PStatus)
	}

	return response.OutParams.PCursor.Rows, nil
}

// UpdateStatusSent calls SP_B via pool service
func (r *catServiceRepository) UpdateStatusSent(ctx context.Context, recordIDs []string, jobID string) error {
	if len(recordIDs) == 0 {
		return nil
	}
	// APM config
	span, ctx := apm.StartSpan(ctx, "catService.repository.UpdateStatusSent", "repository")
	defer span.End()
	span.Context.SetLabel("JobID", jobID)

	ids := strings.Join(recordIDs, ",")
	statement := `BEGIN APP_ESB_MICROSVC.SP_CAT_UPDATE_STATUS_SENT(:P_RECORD_IDS, :P_JOB_ID, :P_STATUS); END;`

	req := &model.PoolServiceRequest{
		Sys: model.SysReq{
			TransID:     jobID,
			RequestorID: r.cfg.App,
			DateTime:    time.Now().Format(time.RFC3339),
		},
		QueryString: statement,
		InputParameters: []model.QueryParam{
			{Name: "P_RECORD_IDS", Value: ids, DataType: "VARCHAR2"},
			{Name: "P_JOB_ID", Value: jobID, DataType: "VARCHAR2"},
		},
		OutputParameters: []model.QueryParam{
			{Name: "P_STATUS", Value: "", DataType: "NUMBER"},
		},
	}

	result, err := r.cfAppDbAdapter.PoolExecuteQuery(ctx, req, r.cfg.CfAppDbClient.Username, r.cfg.CfAppDbClient.Password)
	if err != nil {
		r.logger.Error("SP_CAT_UPDATE_STATUS_SENT failed",
			zap.String("JobID", jobID),
			zap.String("RecordIDsStr", ids),
			zap.String("ErrMsg", err.Error()),
		)
		return fmt.Errorf("SP_CAT_UPDATE_STATUS_SENT failed: %w", err)
	}

	pStatus, _ := sonic.GetFromString(result.Results, "out_params", "P_STATUS")
	if statusVal, err := pStatus.Int64(); err == nil && statusVal != 0 {
		r.logger.Error("SP_CAT_UPDATE_STATUS_SENT returned error status",
			zap.String("JobID", jobID),
			zap.String("RecordIDsStr", ids),
			zap.Int64("StatusExeSP", statusVal),
		)
		return fmt.Errorf("SP_CAT_UPDATE_STATUS_SENT returned status: %d", statusVal)
	}
	return nil
}

