package repository

import (
	"context"
	"errors"
	"fmt"
	"strings"
	"testing"

	"cat-service/config"

	dbdto "esb-go-libs/dbadapter/dto"
	model "esb-go-libs/dbadapter/model"

	"github.com/stretchr/testify/assert"
	"go.uber.org/zap"
)

// ─── Mock Pool Adapter ──────────────────────────────────────────

type mockPoolAdapter struct {
	poolExecuteQuery func(ctx context.Context, req *model.PoolServiceRequest, userName, passWord string) (*dbdto.ExecuteQueryResponseDTO, error)
}

func (m *mockPoolAdapter) PoolExecuteQuery(ctx context.Context, req *model.PoolServiceRequest, userName, passWord string) (*dbdto.ExecuteQueryResponseDTO, error) {
	return m.poolExecuteQuery(ctx, req, userName, passWord)
}

// ─── Helpers ────────────────────────────────────────────────────

func newTestRepo(adapter *mockPoolAdapter) *catServiceRepository {
	cfg := &config.Config{}
	cfg.App = "cat-service-test"
	cfg.CfAppDbClient.Username = "testuser"
	cfg.CfAppDbClient.Password = "testpass"

	return &catServiceRepository{
		cfg:            cfg,
		logger:         zap.NewNop(),
		cfAppDbAdapter: adapter,
	}
}

// ─── CaptureRecords ─────────────────────────────────────────────

func TestCaptureRecords_Success(t *testing.T) {
	adapter := &mockPoolAdapter{
		poolExecuteQuery: func(ctx context.Context, req *model.PoolServiceRequest, userName, passWord string) (*dbdto.ExecuteQueryResponseDTO, error) {
			assert.Equal(t, "testuser", userName)
			assert.Equal(t, "testpass", passWord)
			assert.Contains(t, req.QueryString, "SP_CAT_CAPTURE_REPAYMENTS")
			return &dbdto.ExecuteQueryResponseDTO{
				Results: `{"out_params":{"P_STATUS":0,"P_CURSOR":{"rows":[{"ID":"1","CONTRACT_NUM":"C001","TRANS_AMOUNT":"5000","TRANS_CODE":"TC1","EX_CHANNEL":"ESB","TRANS_TYPE":"CARD","TRANS_DATE":"2026-01-01","TRANS_DESC":"test","EX_COMPANY":"CO1","STATUS":"ORIG","RETRY_COUNT":"0"},{"ID":"2","CONTRACT_NUM":"C002","TRANS_AMOUNT":"3000","TRANS_CODE":"TC2","EX_CHANNEL":"ESB","TRANS_TYPE":"CARD","TRANS_DATE":"2026-01-01","TRANS_DESC":"test2","EX_COMPANY":"CO1","STATUS":"RETRY","RETRY_COUNT":"1"}]}}}`,
			}, nil
		},
	}
	repo := newTestRepo(adapter)

	records, err := repo.CaptureRecords(context.Background(), "job-123", 100, 60)
	assert.NoError(t, err)
	assert.Len(t, records, 2)
	assert.Equal(t, "1", records[0].ID)
	assert.Equal(t, "C001", records[0].ContractNum)
	assert.Equal(t, "5000", records[0].TransAmount)
	assert.Equal(t, "ORIG", records[0].Status)
	assert.Equal(t, "2", records[1].ID)
	assert.Equal(t, "RETRY", records[1].Status)
}

func TestCaptureRecords_NothingToProcess(t *testing.T) {
	adapter := &mockPoolAdapter{
		poolExecuteQuery: func(ctx context.Context, req *model.PoolServiceRequest, userName, passWord string) (*dbdto.ExecuteQueryResponseDTO, error) {
			return &dbdto.ExecuteQueryResponseDTO{
				Results: `{"out_params":{"P_STATUS":3,"P_CURSOR":{"rows":[]}}}`,
			}, nil
		},
	}
	repo := newTestRepo(adapter)

	records, err := repo.CaptureRecords(context.Background(), "job-123", 100, 60)
	assert.NoError(t, err)
	assert.Nil(t, records)
}

