// ─── UpdateStatusRetry ──────────────────────────────────────────

func TestUpdateStatusRetry_EmptyIDs(t *testing.T) {
	repo := newTestRepo(&mockPoolAdapter{})
	err := repo.UpdateStatusRetry(context.Background(), []string{}, "RE1", "job-123")
	assert.NoError(t, err)
}

func TestUpdateStatusRetry_Success(t *testing.T) {
	adapter := &mockPoolAdapter{
		poolExecuteQuery: func(ctx context.Context, req *model.PoolServiceRequest, userName, passWord string) (*dbdto.ExecuteQueryResponseDTO, error) {
			assert.Contains(t, req.QueryString, "SP_CAT_UPDATE_STATUS_RETRY")
			// Verify retry status is passed
			for _, p := range req.InputParameters {
				if p.Name == "P_RETRY_STATUS" {
					assert.Equal(t, "RE2", p.Value)
				}
			}
			return &dbdto.ExecuteQueryResponseDTO{Results: `{"out_params":{"P_STATUS":0}}`}, nil
		},
