package usecase

import (
	"context"
	"fmt"
	"os"
	"strconv"
	"sync"
	"time"

	"cat-service/config"
	"cat-service/internal/adapter"
	"cat-service/internal/adapter/model"
	"cat-service/internal/common"
	"cat-service/internal/dto"
	"cat-service/internal/repository"
	"cat-service/internal/util"

	"go.elastic.co/apm/v2"
	"go.uber.org/zap"
)

type ICatServiceUsecase interface {
	Run(ctx context.Context) error
}

type catServiceUsecase struct {
	cfg    *config.Config
	repo   repository.ICatServiceRepository
	client adapter.IW4PaymentServiceClient
	logger *zap.Logger
}

func NewCatServiceUsecase(
	cfg *config.Config,
	repo repository.ICatServiceRepository,
	client adapter.IW4PaymentServiceClient,
	logger *zap.Logger,
) ICatServiceUsecase {
	return &catServiceUsecase{
		cfg:    cfg,
		repo:   repo,
		client: client,
		logger: logger,
	}
}

func (u *catServiceUsecase) Run(ctx context.Context) error {
	// APM config
	span, ctx := apm.StartSpan(ctx, "catService.usecase.Run", "usecase")
	defer span.End()

	jobID := util.GenJobID()
	hostname, _ := os.Hostname()
	span.Context.SetLabel("JobID", jobID)
	span.Context.SetLabel("HostName", hostname)

	// define limit for a run of job, never reach 30000 per run
	totalLimit := min(max(u.cfg.JobCfg.TotalRecordsPerRun, u.cfg.JobCfg.BatchSize), u.cfg.JobCfg.MaximumRecordsPerRun)

	u.logger.Debug("Job started",
		zap.String("JobID", jobID),
		zap.String("HostName", hostname),
		zap.Int("TotalRecordsPerRun", totalLimit),
		zap.Int("BatchSize", u.cfg.JobCfg.BatchSize),
	)

	// Step 1: Start tick goroutine to extend release_at
	tickCtx, tickCancel := context.WithCancel(ctx)
	defer tickCancel()

	var tickWg sync.WaitGroup
	tickWg.Add(1)
	go u.tickJob(tickCtx, &tickWg, jobID)

	// Step 2: Capture and process in batch loops until totalLimit or no records
	chunkSize := u.cfg.JobCfg.ChunkSize
	tickInterval := time.Duration(u.cfg.JobCfg.TickIntervalSeconds) * time.Second
	workerCount := max(u.cfg.JobCfg.WorkerCount, 1)
	recordsPerRequest := max(u.cfg.W4PaymentServiceCfg.RecordsPerRequest, 1)

	totalProcessed := 0
	var allRetryIDs []string

	for totalProcessed < totalLimit {
		// Capture a batch
		records, err := u.repo.CaptureRecords(
			ctx,
			jobID,
			u.cfg.JobCfg.BatchSize,
			u.cfg.JobCfg.ReleaseExtendSeconds,
		)
		if err != nil {
			tickCancel()
			tickWg.Wait()
			return fmt.Errorf("failed to capture records: %w", err)
		}

		if len(records) == 0 {
			u.logger.Debug("No more records to process",
				zap.String("JobID", jobID),
				zap.Int("TotalProcessed", totalProcessed),
			)
			break
		}

		u.logger.Debug("Captured batch",
			zap.String("JobID", jobID),
			zap.Int("BatchCount", len(records)),
			zap.Int("TotalProcessed", totalProcessed),
		)

		// Process batch with worker pool
		batchRetryIDs := u.processBatch(ctx, records, jobID, hostname, workerCount, recordsPerRequest, chunkSize, tickInterval)
		allRetryIDs = append(allRetryIDs, batchRetryIDs...)
		totalProcessed += len(records)
	}

	// Stop tick job
	tickCancel()
	tickWg.Wait()

	// SP_D: Update RETRY after all batches done (so retries aren't re-captured in same run)
	if len(allRetryIDs) > 0 {
		if err := u.repo.UpdateStatusRetry(ctx, allRetryIDs, common.StatusRetry, jobID); err != nil {
			u.logger.Error("Failed to update retry status",
				zap.String("JobID", jobID),
				zap.String("ErrMsg", err.Error()),
			)
		}
	}

	// Sync final statuses (SENT/FAIL) back to REP_PAYMENTS
	if totalProcessed > 0 {
		if err := u.repo.SyncStatusToMain(ctx, jobID); err != nil {
			u.logger.Error("Failed to sync status to main table",
				zap.String("JobID", jobID),
				zap.String("HostName", hostname),
				zap.String("ErrMsg", err.Error()),
			)
			return fmt.Errorf("failed to sync status to main: %w", err)
		}
	}

	u.logger.Info(
		"Job completed successfully",
		zap.String("JobID", jobID),
		zap.String("HostName", hostname),
		zap.Int("TotalProcessed", totalProcessed),
	)
	return nil
}

// processBatch processes a single batch of records with worker pool, returns retry IDs
func (u *catServiceUsecase) processBatch(ctx context.Context, records []dto.Record, jobID, hostname string, workerCount, recordsPerRequest, chunkSize int, tickInterval time.Duration) []string {
	jobs := make(chan []dto.Record, len(records)/recordsPerRequest+1)
	resultsCh := make(chan model.ProcessResult, len(records))

	var workerWg sync.WaitGroup
	for range workerCount {
		workerWg.Add(1)
		go func() {
			defer workerWg.Done()
			for batch := range jobs {
				batchResults := u.client.ProcessRecords(ctx, batch)
				for _, r := range batchResults {
					resultsCh <- r
				}
			}
		}()
	}

	// Send records in batches to workers
	for i := 0; i < len(records); i += recordsPerRequest {
		end := min(i+recordsPerRequest, len(records))
		jobs <- records[i:end]
	}
	close(jobs)

	// Close results channel when all workers done
	go func() {
		workerWg.Wait()
		close(resultsCh)
	}()

	// Fan-in: collect results and flush by chunk size or tick interval
	var pendingResults []model.ProcessResult
	var batchRetryIDs []string
	lastFlush := time.Now()
	totalRecords := len(records)
	processedCount := 0

	for result := range resultsCh {
		pendingResults = append(pendingResults, result)
		processedCount++

		chunkFull := len(pendingResults) >= chunkSize
		tickElapsed := time.Since(lastFlush) >= tickInterval
		isLast := processedCount >= totalRecords

		if chunkFull || tickElapsed || isLast {
			retryIDs, err := u.flushResults(ctx, pendingResults, jobID, hostname)
			if err != nil {
				u.logger.Error("Failed to flush results",
					zap.String("JobID", jobID),
					zap.String("HostName", hostname),
					zap.String("ErrMsg", err.Error()),
				)
			}
			batchRetryIDs = append(batchRetryIDs, retryIDs...)
			pendingResults = pendingResults[:0]
			lastFlush = time.Now()
		}
	}

	return batchRetryIDs
}

// tickJob periodically extends release_at for all PROC records owned by this job
func (u *catServiceUsecase) tickJob(ctx context.Context, wg *sync.WaitGroup, jobID string) {
	defer wg.Done()

	ticker := time.NewTicker(time.Duration(u.cfg.JobCfg.TickIntervalSeconds) * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			if err := u.repo.ExtendRelease(ctx, jobID, u.cfg.JobCfg.ReleaseExtendSeconds); err != nil {
				u.logger.Error("Tick: failed to extend release",
					zap.String("JobID", jobID),
					zap.String("ErrMsg", err.Error()),
				)
			} else {
				u.logger.Debug("Tick: extended release_at",
					zap.String("JobID", jobID),
				)
			}
		}
	}
}

// flushResults updates SENT/FAIL statuses. Returns retry IDs (not flushed here).
func (u *catServiceUsecase) flushResults(ctx context.Context, results []model.ProcessResult, jobID string, hostname string) ([]string, error) {
	// APM config
	span, ctx := apm.StartSpan(ctx, "catService.usecase.flushResults", "usecase")
	defer span.End()
	span.Context.SetLabel("JobID", jobID)

	var sentIDs []string
	var failIDs []string
	var retryIDs []string

	for _, r := range results {
		if r.IsSuccess {
			sentIDs = append(sentIDs, r.RecordID)
			continue
		}

		if !r.IsRetryable {
			failIDs = append(failIDs, r.RecordID)
			continue
		}

		// Check if max retry exceeded
		retryCount, _ := strconv.Atoi(r.RetryCount)
		if retryCount+1 > u.cfg.JobCfg.MaxRetry {
			failIDs = append(failIDs, r.RecordID)
		} else {
			retryIDs = append(retryIDs, r.RecordID)
		}
	}

	// SP_B: Update SENT
	if err := u.repo.UpdateStatusSent(ctx, sentIDs, jobID); err != nil {
		return retryIDs, err
	}

	// SP_C: Update FAIL
	if err := u.repo.UpdateStatusFail(ctx, failIDs, jobID); err != nil {
		return retryIDs, err
	}

	u.logger.Info("Flushed chunk results",
		zap.String("JobID", jobID),
		zap.String("HostName", hostname),
		zap.Int("TransactionSent", len(sentIDs)),
		zap.Int("TransactionFail", len(failIDs)),
		zap.Int("TransactionRetry", len(retryIDs)),
	)

	return retryIDs, nil
}

