package util

import (
	"strconv"
	"strings"

	"github.com/google/uuid"
)

func GenJobID() string {
	return uuid.New().String()
}

// Int64SliceToCSV converts a slice of int64 to comma-separated string for Oracle SP
func Int64SliceToCSV(ids []int64) string {
	s := make([]string, len(ids))
	for i, id := range ids {
		s[i] = strconv.FormatInt(id, 10)
	}
	return strings.Join(s, ",")
}

// FormatISOToDateOnly converts "2026-06-09T00:00:00Z" to "09-06-2026" (dd-MM-yyyy)
// Returns the original string if parsing fails.
func FormatISOToDateOnly(isoDate string) string {
	if len(isoDate) < 10 {
		return isoDate
	}
	// isoDate format: "yyyy-MM-ddT..."
	year := isoDate[0:4]
	month := isoDate[5:7]
	day := isoDate[8:10]
	return day + "-" + month + "-" + year
}

