package util

import (
	"testing"

	"github.com/stretchr/testify/assert"
)

func TestGenJobID(t *testing.T) {
	id1 := GenJobID()
	id2 := GenJobID()

	assert.NotEmpty(t, id1)
	assert.NotEmpty(t, id2)
	assert.NotEqual(t, id1, id2, "each job ID should be unique")
	assert.Len(t, id1, 36, "UUID v4 string length should be 36")
}

func TestInt64SliceToCSV(t *testing.T) {
	tests := []struct {
		name     string
		input    []int64
		expected string
	}{
		{name: "empty slice", input: []int64{}, expected: ""},
		{name: "single element", input: []int64{42}, expected: "42"},
		{name: "multiple elements", input: []int64{1, 2, 3}, expected: "1,2,3"},
		{name: "large numbers", input: []int64{1000000000001, 1000000000002}, expected: "1000000000001,1000000000002"},
		{name: "negative numbers", input: []int64{-1, -2, 3}, expected: "-1,-2,3"},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, Int64SliceToCSV(tt.input))
		})
	}
}

func BenchmarkInt64SliceToCSV(b *testing.B) {
	ids := make([]int64, 200)
	for i := range ids {
		ids[i] = int64(i + 1)
	}
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		Int64SliceToCSV(ids)
	}
}

