-- Processing table: shadow table for job lifecycle
-- Main table REP_PAYMENTS cannot be altered
CREATE TABLE APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING (
    id              NUMBER(18) NOT NULL,                    -- PK, references APP_DOMINO.REP_PAYMENTS.id
    contract_num    VARCHAR2(100),                          -- LIAB contract number from REP_PAYMENTS
    trans_amount    NUMBER(20),                             -- payment amount in VND
    trans_code      VARCHAR2(100),                          -- transaction code, used as IpatId in W4 request
    ex_channel      VARCHAR2(20),                           -- external channel (e.g. ESB)
    trans_type      VARCHAR2(4),                            -- transaction type (e.g. CARD)
    trans_date      DATE,                                   -- original transaction date
    trans_desc      VARCHAR2(500),                          -- transaction description
    ex_company      VARCHAR2(20),                           -- external company code
    status          VARCHAR2(10) DEFAULT 'ORIG' NOT NULL,   -- ORIG/PROC/RETRY/SENT/FAIL/SYNCED
    prev_status     VARCHAR2(10),                           -- status before last transition (for crash recovery)
    retry_count     NUMBER(3) DEFAULT 0 NOT NULL,           -- number of times W4 call has been retried
    job_id          VARCHAR2(36),                           -- UUID of the job currently owning this record
    release_at      TIMESTAMP,                             -- heartbeat lock expiry, other pods skip if not expired
    created_at      TIMESTAMP DEFAULT SYSDATE NOT NULL,    -- when record was first captured from REP_PAYMENTS
    updated_at      TIMESTAMP DEFAULT SYSDATE NOT NULL,    -- last status change timestamp
    CONSTRAINT pk_cat_repayment_proc PRIMARY KEY (id)
);

-- Table comment
COMMENT ON TABLE APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING IS 'Shadow processing table for CAT repayment batch job. Tracks lifecycle of records sent to W4 Payment Service.';

-- Column comments
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.id IS 'PK, references APP_DOMINO.REP_PAYMENTS.id';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.contract_num IS 'LIAB contract number from REP_PAYMENTS';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.trans_amount IS 'Payment amount in VND';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.trans_code IS 'Transaction code, used as IpatId in W4 request';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.ex_channel IS 'External channel (e.g. ESB)';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.trans_type IS 'Transaction type (e.g. CARD)';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.trans_date IS 'Original transaction date';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.trans_desc IS 'Transaction description';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.ex_company IS 'External company code';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.status IS 'Record status: ORIG/PROC/RETRY/SENT/FAIL/SYNCED';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.prev_status IS 'Status before last transition, used for crash recovery';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.retry_count IS 'Number of times W4 call has been retried';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.job_id IS 'UUID of the job currently owning this record';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.release_at IS 'Heartbeat lock expiry, other pods skip if not expired';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.created_at IS 'When record was first captured from REP_PAYMENTS';
COMMENT ON COLUMN APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING.updated_at IS 'Last status change timestamp';

-- Index for SP_CAT_CAPTURE_REPAYMENTS record selection (status + release_at)
CREATE INDEX idx_cat_proc_status ON APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING (status, release_at);

-- Index for job ownership queries (tick heartbeat, flush)
CREATE INDEX idx_cat_proc_job ON APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING (job_id, status);

-- Auto-delete records older than 250 days from processing table
CREATE OR REPLACE PROCEDURE APP_ESB_MICROSVC.SP_CAT_CLEANUP_OLD_REPAYMENTS AS
BEGIN
    DELETE FROM APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING
    WHERE created_at < ADD_MONTHS(SYSDATE, -10); -- 10 month saved log, can check by status SYNCED

    COMMIT;
EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        DBMS_OUTPUT.PUT_LINE('SP_CAT_CLEANUP_OLD_REPAYMENTS error: ' || SQLERRM);
END SP_CAT_CLEANUP_OLD_REPAYMENTS;

-- grant access to APP_DOMINO
GRANT SELECT, DELETE ON APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING TO APP_DOMINO;
GRANT EXECUTE ON APP_ESB_MICROSVC.SP_CAT_CLEANUP_OLD_REPAYMENTS TO APP_DOMINO;

-- Schedule daily cleanup via Oracle DBMS_SCHEDULER
BEGIN
    DBMS_SCHEDULER.CREATE_JOB (
        job_name        => 'JOB_CAT_CLEANUP_OLD_REPAYMENTS',
        job_type        => 'STORED_PROCEDURE',
        job_action      => 'APP_ESB_MICROSVC.SP_CAT_CLEANUP_OLD_REPAYMENTS',
        start_date      => SYSTIMESTAMP,
        repeat_interval => 'FREQ=DAILY;BYHOUR=2;BYMINUTE=0;BYSECOND=0',
        enabled         => TRUE,
        comments        => 'Daily cleanup of CAT_REPAYMENT_PROCESSING records older than 200 days'
    );
END;

