-- Generate test data for REP_PAYMENTS
-- Usage: adjust v_count to generate 10000, 50000, etc.
-- Run multiple times with different v_start_id to avoid PK conflicts
-- After testing, run the cleanup block at the bottom to reset

DECLARE
    v_count      PLS_INTEGER := 10000;  -- change to 50000 for larger test
    v_start_id   NUMBER := 90000001;    -- start ID to avoid conflict with real data
    v_batch_size PLS_INTEGER := 1000;   -- commit every N rows
    v_charset    VARCHAR2(64) := 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789_/';
    v_code       VARCHAR2(20);

    FUNCTION random_code(p_len PLS_INTEGER) RETURN VARCHAR2 IS
        v_result VARCHAR2(64);
    BEGIN
        FOR k IN 1..p_len LOOP
            v_result := v_result || SUBSTR(v_charset, FLOOR(DBMS_RANDOM.VALUE(1, 65)), 1);
        END LOOP;
        RETURN v_result;
    END;
BEGIN
    FOR i IN 0..v_count-1 LOOP
        v_code := random_code(16);  -- 16-char random trans_code

        INSERT INTO APP_DOMINO.REP_PAYMENTS (
            id,
            ex_channel,
            trans_type,
            trans_code,
            trans_date,
            trans_amount,
            trans_desc,
            contract_num,
            payment_mode,
            clearing,
            ex_company,
            ex_status,
            createdate
        ) VALUES (
            v_start_id + i,
            'PAY',
            'CARD',
            v_code,                                              -- random alphanumeric + _ + / trans_code
            TRUNC(SYSDATE),
            ROUND(DBMS_RANDOM.VALUE(5000, 50000)),               -- random amount 5k-50k
            'Test repayment #' || i,
            '150004001' || LPAD(TO_CHAR(MOD(i, 9999)), 4, '0'),
            '1',
            '1',
            'COMPANY_A',
            'ORIG',
            SYSDATE
        );

        IF MOD(i + 1, v_batch_size) = 0 THEN
            COMMIT;
            DBMS_OUTPUT.PUT_LINE('Inserted ' || (i + 1) || ' rows...');
        END IF;
    END LOOP;

    COMMIT;
    DBMS_OUTPUT.PUT_LINE('Done. Inserted ' || v_count || ' test rows starting at ID ' || v_start_id);
END;
/

