files.scripts/sp_cat_capture_repayments.sql:
-- SP_CAT_CAPTURE_REPAYMENTS: Capture records for processing
-- 1. Release expired PROC records (crashed pods) and revert main table
-- 2. Capture RETRY records from processing table (re-process)
-- 3. Capture new ORIG records from REP_PAYMENTS
-- 4. Mark main table as PROC, insert new records into processing table
-- 5. Return all captured records via cursor
-- p_status = 0 success, 3 = nothing to process, other = error

CREATE OR REPLACE PROCEDURE APP_ESB_MICROSVC.SP_CAT_CAPTURE_REPAYMENTS (
    p_job_id        IN  VARCHAR2,
    p_batch_size    IN  NUMBER,
    p_release_sec   IN  NUMBER,
    p_status        OUT NUMBER,
    p_cursor        OUT SYS_REFCURSOR
) AS
    TYPE id_table_type IS TABLE OF NUMBER(18);
    v_new_ids       id_table_type;
    v_retry_ids     id_table_type;
    v_released_ids  id_table_type;
    v_total_captured NUMBER := 0;
    v_remaining      NUMBER;
BEGIN
    p_status := 0;

    -- Step 1: Release expired PROC records (crashed pods)
    UPDATE APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING
    SET status = NVL(prev_status, 'ORIG'),
        job_id = NULL,
        release_at = NULL,
        updated_at = SYSDATE
    WHERE status = 'PROC'
      AND release_at < SYSDATE
    RETURNING id BULK COLLECT INTO v_released_ids;

    -- Revert ex_status in main table for released records
    IF v_released_ids.COUNT > 0 THEN
        FORALL i IN 1..v_released_ids.COUNT
            UPDATE APP_DOMINO.REP_PAYMENTS
            SET ex_status = 'ORIG',
                update_ts = SYSDATE
            WHERE id = v_released_ids(i);
    END IF;

    -- Step 2: Capture RETRY records from processing table using cursor
    DECLARE
        CURSOR c_retry IS
            SELECT id
            FROM APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING
            WHERE status = 'RETRY'
              AND (release_at IS NULL OR release_at < SYSDATE)
            ORDER BY updated_at ASC
            FOR UPDATE SKIP LOCKED;
        v_id NUMBER(18);
        v_cnt PLS_INTEGER := 0;
    BEGIN
        v_retry_ids := id_table_type();
        OPEN c_retry;
        LOOP
            FETCH c_retry INTO v_id;
            EXIT WHEN c_retry%NOTFOUND OR v_cnt >= p_batch_size;
            v_cnt := v_cnt + 1;
            v_retry_ids.EXTEND;
            v_retry_ids(v_cnt) := v_id;
        END LOOP;
        CLOSE c_retry;
    END;

    -- Lock retry records
    IF v_retry_ids.COUNT > 0 THEN
        FORALL i IN 1..v_retry_ids.COUNT
            UPDATE APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING
            SET prev_status = status,
                status = 'PROC',
                job_id = p_job_id,
                release_at = SYSDATE + NUMTODSINTERVAL(p_release_sec, 'SECOND'),
                updated_at = SYSDATE
            WHERE id = v_retry_ids(i);
    END IF;

    v_total_captured := v_retry_ids.COUNT;
    v_remaining := p_batch_size - v_total_captured;

    -- Step 3: Capture new ORIG records from REP_PAYMENTS (fill remaining batch)
    IF v_remaining > 0 THEN
        DECLARE
            CURSOR c_orig IS
                SELECT id
                FROM APP_DOMINO.REP_PAYMENTS
                WHERE ex_status = 'ORIG'
                  AND trans_type = 'CARD'
                ORDER BY createdate ASC
                FOR UPDATE SKIP LOCKED;
            v_id NUMBER(18);
            v_cnt PLS_INTEGER := 0;
        BEGIN
            v_new_ids := id_table_type();
            OPEN c_orig;
            LOOP
                FETCH c_orig INTO v_id;
                EXIT WHEN c_orig%NOTFOUND OR v_cnt >= v_remaining;
                v_cnt := v_cnt + 1;
                v_new_ids.EXTEND;
                v_new_ids(v_cnt) := v_id;
            END LOOP;
            CLOSE c_orig;
        END;

        IF v_new_ids.COUNT > 0 THEN
            -- Mark main table as PROC
            FORALL i IN 1..v_new_ids.COUNT
                UPDATE APP_DOMINO.REP_PAYMENTS
                SET ex_status = 'PROC',
                    update_ts = SYSDATE
                WHERE id = v_new_ids(i);

            -- Insert into processing table
            FORALL i IN 1..v_new_ids.COUNT
                INSERT INTO APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING (id, contract_num, trans_amount, trans_code, ex_channel, trans_type, trans_date, trans_desc, ex_company, status, prev_status, retry_count, job_id, release_at)
                SELECT id, contract_num, trans_amount, trans_code, ex_channel, trans_type, trans_date, trans_desc, ex_company,
                       'PROC', 'ORIG', 0, p_job_id, SYSDATE + NUMTODSINTERVAL(p_release_sec, 'SECOND')
                FROM APP_DOMINO.REP_PAYMENTS
                WHERE id = v_new_ids(i);

            v_total_captured := v_total_captured + v_new_ids.COUNT;
        END IF;
    END IF;

    COMMIT;

    -- Nothing captured
    IF v_total_captured = 0 THEN
        p_status := 3;
        OPEN p_cursor FOR
            SELECT NULL id, NULL contract_num, NULL trans_amount, NULL trans_code,
                   NULL ex_channel, NULL trans_type, NULL trans_date, NULL trans_desc,
                   NULL ex_company, NULL status, NULL retry_count
            FROM DUAL WHERE 1=0;
        RETURN;
    END IF;

    -- Step 5: Return all captured records
    OPEN p_cursor FOR
        SELECT id, contract_num, trans_amount, trans_code, ex_channel, trans_type, trans_date, trans_desc, ex_company, prev_status AS status, retry_count
        FROM APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING
        WHERE job_id = p_job_id
          AND status = 'PROC';

EXCEPTION
    WHEN OTHERS THEN
        IF p_cursor%ISOPEN THEN
            CLOSE p_cursor;
        END IF;
        ROLLBACK;
        p_status := SQLCODE;
        DBMS_OUTPUT.PUT_LINE('SP_CAT_CAPTURE_REPAYMENTS error: ' || SQLERRM);
END SP_CAT_CAPTURE_REPAYMENTS;

files.scripts/sp_cat_extend_release.sql:
-- SP_CAT_EXTEND_RELEASE: Extend release_at for all PROC records owned by this job (tick heartbeat)
-- p_status = 0 success, other = fail

CREATE OR REPLACE PROCEDURE APP_ESB_MICROSVC.SP_CAT_EXTEND_RELEASE (
    p_job_id      IN VARCHAR2,
    p_extend_sec  IN NUMBER,
    p_status      OUT NUMBER
) AS
BEGIN
    p_status := 0;

    UPDATE APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING
    SET release_at = SYSDATE + NUMTODSINTERVAL(p_extend_sec, 'SECOND')
    WHERE job_id = p_job_id
      AND status = 'PROC';

    COMMIT;

EXCEPTION
    WHEN OTHERS THEN
