-- SP_CAT_UPDATE_STATUS_FAIL: Update records status to FAIL (batch via CSV IDs)
-- Uses fast CSV splitter (O(n) vs REGEXP O(n²))
-- p_status = 0 success, other = fail

CREATE OR REPLACE PROCEDURE APP_ESB_MICROSVC.SP_CAT_UPDATE_STATUS_FAIL (
    p_record_ids IN VARCHAR2,
    p_job_id     IN VARCHAR2,
    p_status     OUT NUMBER
) AS
    TYPE id_table_type IS TABLE OF NUMBER(18);
    v_ids       id_table_type := id_table_type();
    v_str       VARCHAR2(32767) := p_record_ids || ',';
    v_pos       PLS_INTEGER := 1;
    v_next      PLS_INTEGER;
BEGIN
    p_status := 0;

    -- Fast CSV split using INSTR (O(n))
    LOOP
        v_next := INSTR(v_str, ',', v_pos);
        EXIT WHEN v_next = 0;
        v_ids.EXTEND;
        v_ids(v_ids.COUNT) := TO_NUMBER(SUBSTR(v_str, v_pos, v_next - v_pos));
        v_pos := v_next + 1;
    END LOOP;

    -- Bulk update processing table
    FORALL i IN 1..v_ids.COUNT
        UPDATE APP_ESB_MICROSVC.CAT_REPAYMENT_PROCESSING
        SET status = 'FAIL',
            prev_status = status,
            release_at = NULL,
            updated_at = SYSDATE
        WHERE id = v_ids(i)
          AND job_id = p_job_id
          AND status = 'PROC';

    COMMIT;

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        p_status := SQLCODE;
        DBMS_OUTPUT.PUT_LINE('SP_CAT_UPDATE_STATUS_FAIL error: ' || SQLERRM);
END SP_CAT_UPDATE_STATUS_FAIL;

